        return json.load(f)


def load_solution(path: Path) -> Dict[str, Any]:
    """Load solution JSON file."""
    with open(path) as f:
        return json.load(f)


def load_ground_truth(path: Path) -> Dict[str, Any]:
    """Load ground truth JSON file."""
